import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { Routes, Route, Link, useNavigate, Navigate } from 'react-router-dom';
import axios from 'axios';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './components/Register';

/* ── Axios defaults ───────────────────────────────────────────── */
axios.defaults.baseURL = 'http://localhost:5000';
axios.defaults.withCredentials = true;

/* ── Auth Context ─────────────────────────────────────────────── */
const AuthContext = createContext(null);
export const useAuth = () => useContext(AuthContext);

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchUser = useCallback(async () => {
    try {
      const res = await axios.get('/api/me');
      setUser(res.data);
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchUser(); }, [fetchUser]);

  const login = async (email, password) => {
    const res = await axios.post('/api/login', { email, password });
    setUser(res.data.user);
    return res.data;
  };

  const register = async (data) => {
    const res = await axios.post('/api/register', data);
    return res.data;
  };

  const logout = async () => {
    await axios.post('/api/logout');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout, fetchUser }}>
      {children}
    </AuthContext.Provider>
  );
}

/* ── Protected Route ──────────────────────────────────────────── */
function ProtectedRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return <div style={{textAlign:'center',padding:'4rem'}}>Loading...</div>;
  if (!user) return <Navigate to="/login" />;
  return children;
}

/* ── Navbar ───────────────────────────────────────────────────── */
function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>🏥 Arogya</Link>
      <div style={styles.navLinks}>
        <Link to="/" style={styles.navLink}>Home</Link>
        {user ? (
          <>
            <Link to="/dashboard" style={styles.navLink}>Dashboard</Link>
            <Link to="/appointments" style={styles.navLink}>My Appointments</Link>
            <Link to="/notifications" style={styles.navLink}>Notifications</Link>
            <button onClick={handleLogout} style={styles.navBtn}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.navLink}>Login</Link>
            <Link to="/register" style={styles.navLinkHighlight}>Sign Up</Link>
          </>
        )}
      </div>
    </nav>
  );
}

/* ── Patient Dashboard ────────────────────────────────────────── */
function PatientDashboard() {
  const { user } = useAuth();
  const [doctors, setDoctors] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [slots, setSlots] = useState([]);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [message, setMessage] = useState('');
  const [notes, setNotes] = useState('');

  useEffect(() => {
    axios.get('/api/doctors', { params: { q: search } })
      .then(r => setDoctors(r.data)).catch(() => {});
  }, [search]);

  const fetchSlots = async (docId, d) => {
    try {
      const r = await axios.get(`/api/doctors/${docId}/slots`, { params: { date: d } });
      setSlots(r.data.slots);
    } catch { setSlots([]); }
  };

  const selectDoctor = (doc) => {
    setSelectedDoctor(doc);
    fetchSlots(doc.id, date);
    setMessage('');
  };

  const handleDateChange = (e) => {
    const d = e.target.value;
    setDate(d);
    if (selectedDoctor) fetchSlots(selectedDoctor.id, d);
  };

  const bookSlot = async (time) => {
    try {
      await axios.post('/api/appointments', {
        doctor_id: selectedDoctor.id, date, time_slot: time, notes
      });
      setMessage(`✅ Appointment booked with Dr. ${selectedDoctor.name} on ${date} at ${time}`);
      fetchSlots(selectedDoctor.id, date);
      setNotes('');
    } catch (err) {
      setMessage(`❌ ${err.response?.data?.error || 'Booking failed'}`);
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>Welcome, {user?.name}!</h1>
      <p style={styles.subtitle}>Find a doctor and book your appointment</p>

      {message && <div style={{...styles.alert, background: message.startsWith('✅') ? '#d1e7dd' : '#f8d7da', color: message.startsWith('✅') ? '#0f5132' : '#842029'}}>{message}</div>}

      {/* Search */}
      <div style={styles.searchBox}>
        <input
          type="text" placeholder="Search doctors by name or specialization..."
          value={search} onChange={e => setSearch(e.target.value)}
          style={styles.searchInput}
        />
      </div>

      <div style={styles.dashGrid}>
        {/* Doctor List */}
        <div>
          <h2 style={styles.sectionTitle}>Available Doctors</h2>
          <div style={styles.doctorList}>
            {doctors.length === 0 ? (
              <p style={{color:'#6c757d', textAlign:'center', padding:'2rem'}}>No doctors found</p>
            ) : doctors.map(doc => (
              <div key={doc.id}
                style={{...styles.docCard, border: selectedDoctor?.id === doc.id ? '2px solid #0d6efd' : '2px solid transparent'}}
                onClick={() => selectDoctor(doc)}>
                <div style={styles.docAvatar}>{doc.name.charAt(0)}</div>
                <div>
                  <h3 style={{margin:0, fontSize:'1rem'}}>Dr. {doc.name}</h3>
                  <p style={{margin:'0.15rem 0', color:'#6c757d', fontSize:'0.85rem'}}>{doc.specialization} • {doc.department}</p>
                  <p style={{margin:0, color:'#6c757d', fontSize:'0.8rem'}}>{doc.experience} yrs exp • {doc.slot_duration} min slots</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Booking Panel */}
        <div>
          {selectedDoctor ? (
            <div style={styles.bookingPanel}>
              <h2 style={styles.sectionTitle}>Book with Dr. {selectedDoctor.name}</h2>
              <p style={{color:'#6c757d', marginBottom:'1rem'}}>{selectedDoctor.specialization} • {selectedDoctor.working_hours_start} – {selectedDoctor.working_hours_end}</p>

              <label style={styles.label}>Select Date</label>
              <input type="date" value={date} onChange={handleDateChange} style={styles.input} min={new Date().toISOString().split('T')[0]} />

              <label style={{...styles.label, marginTop:'1rem'}}>Available Slots</label>
              <div style={styles.slotGrid}>
                {slots.length === 0 ? (
                  <p style={{color:'#6c757d', gridColumn:'1/-1'}}>No slots available for this date</p>
                ) : slots.map(slot => (
                  <button key={slot.time}
                    disabled={!slot.available}
                    onClick={() => bookSlot(slot.time)}
                    style={{...styles.slotBtn, ...(slot.available ? styles.slotAvailable : styles.slotBooked)}}>
                    {slot.time}
                  </button>
                ))}
              </div>

              <label style={{...styles.label, marginTop:'1rem'}}>Notes (optional)</label>
              <textarea value={notes} onChange={e => setNotes(e.target.value)}
                placeholder="Describe your symptoms or reason for visit..."
                style={{...styles.input, minHeight:'80px', resize:'vertical'}} />
            </div>
          ) : (
            <div style={styles.emptyPanel}>
              <h3>Select a Doctor</h3>
              <p>Click on a doctor from the list to see available slots and book an appointment.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Appointments Page ────────────────────────────────────────── */
function AppointmentsPage() {
  const [appointments, setAppointments] = useState([]);
  const [message, setMessage] = useState('');
  const [reschedule, setReschedule] = useState(null);
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');

  const fetchAppts = useCallback(async () => {
    try {
      const r = await axios.get('/api/appointments');
      setAppointments(r.data);
    } catch {}
  }, []);

  useEffect(() => { fetchAppts(); }, [fetchAppts]);

  const cancelAppt = async (id) => {
    if (!window.confirm('Are you sure you want to cancel this appointment?')) return;
    try {
      await axios.put(`/api/appointments/${id}/cancel`);
      setMessage('Appointment cancelled');
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Cancel failed'); }
  };

  const doReschedule = async (id) => {
    try {
      await axios.put(`/api/appointments/${id}/reschedule`, { date: newDate, time_slot: newTime });
      setMessage('Appointment rescheduled');
      setReschedule(null);
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Reschedule failed'); }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>My Appointments</h1>
      {message && <div style={styles.alert}>{message}</div>}

      {appointments.length === 0 ? (
        <div style={styles.emptyPanel}>
          <h3>No Appointments</h3>
          <p>Go to the dashboard to book your first appointment.</p>
        </div>
      ) : (
        <div style={styles.apptList}>
          {appointments.map(a => (
            <div key={a.id} style={styles.apptCard}>
              <div style={styles.apptHeader}>
                <h3 style={{margin:0}}>Dr. {a.doctor_name}</h3>
                <span style={{...styles.badge, ...(a.status === 'confirmed' ? styles.badgeConfirmed : a.status === 'cancelled' ? styles.badgeCancelled : styles.badgeCompleted)}}>
                  {a.status}
                </span>
              </div>
              <p style={{color:'#6c757d', margin:'0.25rem 0'}}>{a.specialization} • {a.department}</p>
              <p style={{margin:'0.25rem 0'}}><strong>📅 {a.date}</strong> at <strong>{a.time_slot}</strong></p>
              {a.notes && <p style={{color:'#6c757d', fontSize:'0.85rem'}}>Notes: {a.notes}</p>}

              {a.status === 'confirmed' && (
                <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                  <button onClick={() => cancelAppt(a.id)} style={styles.btnDanger}>Cancel</button>
                  <button onClick={() => { setReschedule(a.id); setNewDate(a.date); setNewTime(a.time_slot); }}
                    style={styles.btnOutline}>Reschedule</button>
                </div>
              )}

              {reschedule === a.id && (
                <div style={{marginTop:'1rem', padding:'1rem', background:'#f8f9fa', borderRadius:'8px'}}>
                  <label style={styles.label}>New Date</label>
                  <input type="date" value={newDate} onChange={e => setNewDate(e.target.value)} style={styles.input} min={new Date().toISOString().split('T')[0]} />
                  <label style={{...styles.label, marginTop:'0.5rem'}}>New Time Slot</label>
                  <input type="time" value={newTime} onChange={e => setNewTime(e.target.value)} style={styles.input} />
                  <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                    <button onClick={() => doReschedule(a.id)} style={styles.btnPrimary}>Confirm</button>
                    <button onClick={() => setReschedule(null)} style={styles.btnOutline}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── Notifications Page ───────────────────────────────────────── */
function NotificationsPage() {
  const [notifs, setNotifs] = useState([]);

  useEffect(() => {
    axios.get('/api/notifications').then(r => setNotifs(r.data)).catch(() => {});
    axios.put('/api/notifications/read').catch(() => {});
  }, []);

  const typeIcons = { booking: '📅', cancellation: '❌', reschedule: '🔄', system: 'ℹ️', info: 'ℹ️' };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>Notifications</h1>
      {notifs.length === 0 ? (
        <div style={styles.emptyPanel}><h3>No notifications</h3></div>
      ) : (
        <div style={styles.apptList}>
          {notifs.map(n => (
            <div key={n.id} style={{...styles.apptCard, opacity: n.is_read ? 0.7 : 1}}>
              <p style={{margin:0, fontSize:'1.1rem'}}>
                {typeIcons[n.type] || 'ℹ️'} {n.message}
              </p>
              <p style={{margin:'0.25rem 0 0', color:'#6c757d', fontSize:'0.8rem'}}>
                {new Date(n.created_at).toLocaleString()}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── App Root ─────────────────────────────────────────────────── */
export default function App() {
  return (
    <AuthProvider>
      <div style={{minHeight:'100vh', background:'#f0f2f5', fontFamily:"'Inter', system-ui, sans-serif"}}>
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/dashboard" element={<ProtectedRoute><PatientDashboard /></ProtectedRoute>} />
          <Route path="/appointments" element={<ProtectedRoute><AppointmentsPage /></ProtectedRoute>} />
          <Route path="/notifications" element={<ProtectedRoute><NotificationsPage /></ProtectedRoute>} />
        </Routes>
      </div>
    </AuthProvider>
  );
}

